// Hardcoded list of images we care about — kept in sync with docker-compose.yml
// pin step. Each entry: { repo, current, max_patch_drift } where current is
// the tag we currently pin to.
return [
  { repo: 'library/postgres',                  current: '16.13',         max_patch_drift: 5 },
  { repo: 'library/redis',                     current: '7.4.8-alpine',  max_patch_drift: 5 },
  { repo: 'library/caddy',                     current: '2.11.2-alpine', max_patch_drift: 5 },
  { repo: 'netdata/netdata',                   current: 'v2.10.3',       max_patch_drift: 5 },
  { repo: 'hashicorp/vault',                   current: '1.15.6',        max_patch_drift: 10 },
  { repo: 'n8nio/n8n',                         current: '2.18.5',        max_patch_drift: 10 },
  { repo: 'metabase/metabase',                 current: 'v0.60.3.3',     max_patch_drift: 5 },
  { repo: 'grafana/grafana',                   current: '13.0.1',        max_patch_drift: 5 },
  { repo: 'qdrant/qdrant',                     current: 'v1.17.1',       max_patch_drift: 5 },
  { repo: 'authelia/authelia',                 current: '4.39.19',       max_patch_drift: 5 },
  { repo: 'prom/prometheus',                   current: 'v3.11.3',       max_patch_drift: 5 },
  { repo: 'prom/alertmanager',                 current: 'v0.27.0',       max_patch_drift: 5 },
  { repo: 'prometheuscommunity/postgres-exporter', current: 'v0.15.0',   max_patch_drift: 5 },
  { repo: 'ollama/ollama',                     current: '0.22.1',        max_patch_drift: 10 },
  { repo: 'open-webui/open-webui',             current: '0.9.2',         max_patch_drift: 5 }
].map(r => ({ json: r }));

const repo    = $('Pinned images').itemMatching($itemIndex).json.repo;
const current = $('Pinned images').itemMatching($itemIndex).json.current;
const maxDrift= $('Pinned images').itemMatching($itemIndex).json.max_patch_drift;
const tags    = ($json.results || []).map(t => t.name);

// Extract semver-ish parts for comparison. Keep prefixes (v) intact.
function parseSemver(t) {
  const m = String(t).match(/v?(\d+)\.(\d+)\.(\d+)(?:[.-]([\w]+))?/);
  if (!m) return null;
  return { maj: +m[1], min: +m[2], patch: +m[3], extra: m[4] || '', raw: t };
}

const cur = parseSemver(current);
if (!cur) {
  return { json: { repo, current, latest: null, drift: null, status: 'unparseable_current' } };
}

// Find tags with same major + same suffix-flavour (alpine/-r etc) when present
const suffix = current.match(/-[a-z]+/)?.[0] || '';
const sameMajor = tags
  .filter(t => t.includes(suffix) || (!suffix && !/[a-z]/.test(t.replace(/^v/, '').replace(/[\d.]/g, ''))))
  .map(parseSemver)
  .filter(p => p && p.maj === cur.maj);

if (sameMajor.length === 0) {
  return { json: { repo, current, latest: null, drift: null, status: 'no_candidates' } };
}

sameMajor.sort((a, b) => (b.min - a.min) || (b.patch - a.patch));
const newest = sameMajor[0];

// Drift = newest minor.patch ahead of current
const drift = (newest.min - cur.min) * 1000 + (newest.patch - cur.patch);
const behind = drift > 0;
const over   = drift > maxDrift;

return { json: {
  repo, current,
  latest: newest.raw,
  drift,
  status: !behind ? 'ok' : (over ? 'over_threshold' : 'behind_within_threshold')
} };

const items = $input.all().map(i => i.json);
const over   = items.filter(i => i.status === 'over_threshold');
const behind = items.filter(i => i.status === 'behind_within_threshold');
const errors = items.filter(i => i.status !== 'ok' && i.status !== 'over_threshold' && i.status !== 'behind_within_threshold');
return [{ json: { items, over, behind, errors, anyOver: over.length > 0 } }];

const r  = $('Aggregate').first().json;
const tg = $('Vault').first().json.data.data;

const lines = ['<b>Image audit — monthly</b>', ''];
if (r.over.length) {
  lines.push('<b>Over drift threshold (action required):</b>');
  for (const i of r.over) lines.push(`• ${i.repo}: ${i.current} → ${i.latest} (drift ${i.drift})`);
  lines.push('');
}
if (r.behind.length) {
  lines.push('<b>Behind, within threshold:</b>');
  for (const i of r.behind) lines.push(`• ${i.repo}: ${i.current} → ${i.latest}`);
  lines.push('');
}
if (!r.over.length && !r.behind.length) {
  lines.push('All pinned images on the latest minor/patch within their major. Nothing to do.');
}
if (r.errors.length) {
  lines.push('<b>Could not check:</b>');
  for (const i of r.errors) lines.push(`• ${i.repo}: ${i.status}`);
}
return [{ json: { chat_id: tg.chat_id, bot_token: tg.bot_token, text: lines.join('\n') } }];
